    "Change GIF alt text from simply being 'GIF' to containing the gif tags / filename": { fr: "Changer le texte alternatif GIF de simplement « GIF » à contenir les balises GIF/nom de fichier", es: "Cambie el texto alternativo del GIF de ser simplemente 'GIF' a contener las etiquetas gif/nombre de archivo", ru: "Измените альтернативный текст GIF с простого «GIF» на содержащий теги gif / имя файла.", zh: "将 GIF 替代文本从简单的“GIF”更改为包含 gif 标签/文件名" },
    "Change the Help (?) toolbar button (top right in chat) to Discord's developer menu": { fr: "Remplacez le bouton Aide (?) de la barre d'outils (en haut à droite dans le chat) par le menu développeur de Discord.", es: "Cambie el botón Ayuda (?) de la barra de herramientas (arriba a la derecha en el chat) al menú de desarrollador de Discord", ru: "Измените кнопку панели инструментов «Справка» (?) (вверху справа в чате) на меню разработчика Discord.", zh: "将帮助 (?) 工具栏按钮（聊天右上角）更改为 Discord 的开发者菜单" },
    "Change the button to view the raw content/data of any message.": { fr: "Modifiez le bouton pour afficher le contenu/les données brutes de n'importe quel message.", es: "Cambie el botón para ver el contenido/datos sin procesar de cualquier mensaje.", ru: "Измените кнопку, чтобы просмотреть необработанное содержимое/данные любого сообщения.", zh: "更改按钮以查看任何消息的原始内容/数据。" },
    "Change the mode of the filter list": { fr: "Changer le mode de la liste de filtres", es: "Cambiar el modo de la lista de filtros.", ru: "Изменение режима списка фильтров", zh: "更改过滤器列表的模式" },
    "Change the type of snow displayed (Affects performance).": { fr: "Modifiez le type de neige affiché (affecte les performances).", es: "Cambia el tipo de nieve que se muestra (Afecta al rendimiento).", ru: "Измените тип отображаемого снега (влияет на производительность).", zh: "更改显示的雪类型（影响性能）。" },
    "Changes the first Letter of each Sentence in Message Inputs to Uppercase": { fr: "Change la première lettre de chaque phrase dans les entrées de message en majuscules", es: "Cambia la primera letra de cada oración en las entradas de mensajes a mayúsculas", ru: "Изменяет первую букву каждого предложения во входных сообщениях на прописные.", zh: "将消息输入中每个句子的第一个字母更改为大写" },
    "Changes the home button to a typing indicator if someone in your dms is typing": { fr: "Transforme le bouton d'accueil en indicateur de saisie si quelqu'un dans votre SMS est en train de taper", es: "Cambia el botón de inicio a un indicador de escritura si alguien en tu DM está escribiendo", ru: "Заменяет кнопку «Домой» индикатором набора текста, если кто-то в вашем dms печатает", zh: "如果您的 dms 中有人正在打字，则将主页按钮更改为打字指示器" },
    "Channel ID copied!": { fr: "ID de chaîne copié !", es: "ID del canal copiado!", ru: "Идентификатор канала скопирован!", zh: "频道 ID 已复制！" },
