    "Claim Cooldown": { fr: "Temps de recharge pour réclamer", es: "Reclamar tiempo de reutilización", ru: "Заявить о перезарядке", zh: "领取冷却时间" },
    "CleanChannelName": { fr: "CleanChannelName", es: "Nombre de canal limpio", ru: "CleanChannelName", zh: "清洁频道名称" },
