    "Close palette after executing a command.": { fr: "Fermez la palette après avoir exécuté une commande.", es: "Cerrar la paleta después de ejecutar un comando.", ru: "Закрыть палитру после выполнения команды.", zh: "执行命令后关闭调色板。" },
