    "Color chat messages based on the author's role color": { fr: "Messages de discussion en couleur basés sur la couleur du rôle de l'auteur", es: "Colorea los mensajes de chat según el color del rol del autor.", ru: "Цветные сообщения чата в зависимости от цвета роли автора", zh: "根据作者的角色颜色对聊天消息进行颜色设置" },
    "Color it red on open": { fr: "Colorie-le en rouge à l'ouverture", es: "Coloréalo de rojo al abrirlo.", ru: "Раскрась его в красный цвет при открытии.", zh: "打开时将其颜色为红色" },
