    "Context menu to dump and download a server's emojis and stickers.": { fr: "Menu contextuel pour vider et télécharger les emojis et autocollants d'un serveur.", es: "Menú contextual para volcar y descargar los emojis y stickers de un servidor.", ru: "Контекстное меню для сброса и загрузки смайлов и стикеров сервера.", zh: "用于转储和下载服务器的表情符号和贴纸的上下文菜单。" },
    "Control voice settings right from the voice panel": { fr: "Contrôlez les paramètres vocaux directement depuis le panneau vocal", es: "Controle la configuración de voz directamente desde el panel de voz", ru: "Управляйте настройками голоса прямо с голосовой панели", zh: "直接从语音面板控制语音设置" },
    "Control whether to always or never get pinged on message replies, with whitelist and blacklist features": { fr: "Contrôlez si vous souhaitez toujours ou jamais recevoir une requête ping sur les réponses aux messages, avec des fonctionnalités de liste blanche et de liste noire.", es: "Controle si se le hará ping siempre o nunca en las respuestas a los mensajes, con funciones de lista blanca y lista negra", ru: "Управляйте тем, всегда или никогда не получать пинги на ответы на сообщения, с помощью функций белого и черного списков.", zh: "使用白名单和黑名单功能控制是否始终或从不收到消息回复 ping" },
    "Controls the default sorting in the diagnostics table.": { fr: "Contrôle le tri par défaut dans la table de diagnostic.", es: "Controla la clasificación predeterminada en la tabla de diagnóstico.", ru: "Управляет сортировкой по умолчанию в таблице диагностики.", zh: "控制诊断表中的默认排序。" },
    "Convert a music link to other streaming platforms.": { fr: "Convertissez un lien musical vers d’autres plateformes de streaming.", es: "Convierte un enlace de música a otras plataformas de streaming.", ru: "Конвертируйте музыкальную ссылку на другие потоковые платформы.", zh: "将音乐链接转换为其他流媒体平台。" },
    "Converts Discord's webpack sources into a tarball.": { fr: "Convertit les sources du webpack de Discord en une archive tar.", es: "Convierte las fuentes del paquete web de Discord en un tarball.", ru: "Конвертирует исходные коды веб-пакета Discord в архив.", zh: "将 Discord 的 webpack 源转换为 tarball。" },
    "Converts an image or video to GIF and sends it in the current channel.": { fr: "Convertit une image ou une vidéo en GIF et l'envoie dans la chaîne actuelle.", es: "Convierte una imagen o vídeo a GIF y lo envía en el canal actual.", ru: "Преобразует изображение или видео в GIF и отправляет его в текущий канал.", zh: "将图像或视频转换为 GIF 并在当前频道中发送。" },
    "Converts metric units to Imperal units and vice versa": { fr: "Convertit les unités métriques en unités impériales et vice versa", es: "Convierte unidades métricas a unidades imperiales y viceversa.", ru: "Преобразует метрические единицы в имперские и наоборот.", zh: "将公制单位转换为英制单位，反之亦然" },
    "Cooldown": { fr: "Temps de recharge", es: "Enfriamiento", ru: "Остывать", zh: "冷却" },
    "Cooldown between claims in seconds (0 = no cooldown).": { fr: "Temps de recharge entre les réclamations en secondes (0 = pas de temps de recharge).", es: "Tiempo de reutilización entre reclamos en segundos (0 = sin tiempo de reutilización).", ru: "Время восстановления между требованиями в секундах (0 = время восстановления отсутствует).", zh: "索赔之间的冷却时间（以秒为单位）（0 = 无冷却时间）。" },
    "Cooldown between replies to the same user (seconds). 0 = no limit.": { fr: "Temps de recharge entre les réponses au même utilisateur (secondes). 0 = aucune limite.", es: "Tiempo de recuperación entre respuestas al mismo usuario (segundos). 0 = sin límite.", ru: "Время восстановления между ответами одному и тому же пользователю (в секундах). 0 = нет ограничений.", zh: "对同一用户的回复之间的冷却时间（秒）。 0 = 无限制。" },
    "Copied!": { fr: "Copié!", es: "¡Copiado!", ru: "Скопировано!", zh: "复制了！" },
