    "Copy Role Color In Profile Popout": { fr: "Copier la couleur du rôle dans la fenêtre contextuelle du profil", es: "Copiar color de rol en la ventana emergente de perfil", ru: "Копировать цвет роли во всплывающем окне профиля", zh: "在配置文件弹出窗口中复制角色颜色" },
    "Copy Unicode": { fr: "Copier Unicode", es: "Copiar Unicode", ru: "Копировать Юникод", zh: "复制统一码" },
