    "Désactiver l'animation des emojis Discord": { fr: "Désactiver l'animation des emojis Discord", es: "Desactivar la animación de emojis Discord", ru: "Деактивация анимации смайлов Discord", zh: "停用 Discord 表情符号动画" },
    "Désactiver la prévisualisation audio du soundboard au survol": { fr: "Désactiver la prévisualisation audio du soundboard au survol", es: "Desactivar la visualización previa del audio de la caja de resonancia en el survol", ru: "Деактивация предварительной визуализации звука звуковой панели в режиме Survol", zh: "取消音板和音频预览音频的激活" },
    "Désactiver les animations spring de l'interface Discord (boutons, modals, etc.)": { fr: "Désactiver les animations spring de l'interface Discord (boutons, modaux, etc.)", es: "Desactivar las animaciones de primavera de la interfaz Discord (botones, modales, etc.)", ru: "Деактивация анимации пружины интерфейса Discord (кнопки, модальные окна и т. д.)", zh: "停用 Discord 界面弹簧动画（按钮、模态框等）" },
    "Désactiver les points \"X est en train d'écrire...\"": { fr: "Désactiver les points \"X est en train d'écrire...\"", es: "Desactivar los puntos \"X est en train d'écrire...\"", ru: "Отключить точки «X est en train d'écrire...»", zh: "取消激活点“X est en train d'écrire...”" },
