    "Edited": { fr: "Modifié", es: "Editado", ru: "Отредактировано", zh: "已编辑" },
    "Email address (local display)": { fr: "Adresse e-mail (affichage local)", es: "Dirección de correo electrónico (visualización local)", ru: "Адрес электронной почты (локальный дисплей)", zh: "电子邮件地址（本地显示）" },
    "Embed": { fr: "Intégrer", es: "Insertar", ru: "Встроить", zh: "嵌入" },
