    "Friend Direct Messages Show Member Count": { fr: "Messages directs d'amis Afficher le nombre de membres", es: "Mensajes directos de amigos muestran el recuento de miembros", ru: "В личных сообщениях друзей отображается количество участников", zh: "好友私信显示会员数" },
    "Friend Direct Messages Show Members": { fr: "Messages directs des amis Afficher les membres", es: "Mensajes directos de amigos Mostrar miembros", ru: "Личные сообщения друзей Показать участников", zh: "好友私信 显示会员" },
    "Friend Direct Messages Silent": { fr: "Messages directs d'amis silencieux", es: "Mensajes directos de amigos en silencio", ru: "Личные сообщения другу без звука", zh: "朋友私信无声" },
