    "GameActivityToggle": { fr: "GameActivityToggle", es: "Alternar actividad del juego", ru: "GameActivityToggle", zh: "游戏活动切换" },
    "Generate FriendCodes to easily add friends": { fr: "Générez des FriendCodes pour ajouter facilement des amis", es: "Genera FriendCodes para agregar amigos fácilmente", ru: "Создавайте коды друзей, чтобы легко добавлять друзей", zh: "生成好友代码，轻松添加好友" },
    "Generates a friend invite link.": { fr: "Génère un lien d'invitation d'ami.", es: "Genera un enlace de invitación de amigo.", ru: "Генерирует ссылку для приглашения друга.", zh: "生成好友邀请链接。" },
    "Generates a random number between two values": { fr: "Génère un nombre aléatoire entre deux valeurs", es: "Genera un número aleatorio entre dos valores.", ru: "Генерирует случайное число между двумя значениями", zh: "生成两个值之间的随机数" },
    "Get a random cat picture": { fr: "Obtenez une photo de chat au hasard", es: "Obtener una imagen de gato aleatoria", ru: "Получить случайное изображение кота", zh: "随机获取一张猫的图片" },
    "Get toasts for when chosen users send a message": { fr: "Obtenez des toasts lorsque des utilisateurs sélectionnés envoient un message", es: "Recibe brindis cuando los usuarios elegidos envían un mensaje", ru: "Получайте всплывающие уведомления о том, когда выбранные пользователи отправляют сообщение.", zh: "当选定的用户发送消息时获得祝酒词" },
