    "Groq API Key (console.groq.com/keys) — shared with AutoCorrect and VoiceDictation": { fr: "Clé API Groq (console.groq.com/keys) — partagée avec AutoCorrect et VoiceDictation", es: "Clave API de Groq (console.groq.com/keys): compartida con Autocorrección y VoiceDictation", ru: "Ключ Groq API (console.groq.com/keys) — используется совместно с AutoCorrect и VoiceDictation.", zh: "Groq API 密钥 (console.groq.com/keys) — 与自动更正和 VoiceDictation 共享" },
    "Group Dm Notifications": { fr: "Notifications de DM de groupe", es: "Notificaciones DM grupales", ru: "Уведомления группы Dm", zh: "群组 Dm 通知" },
    "Group Messages": { fr: "Messages de groupe", es: "Mensajes grupales", ru: "Групповые сообщения", zh: "群组消息" },
    "Group your commonly visited channels in tabs, like a browser": { fr: "Regroupez vos chaînes fréquemment visitées dans des onglets, comme un navigateur", es: "Agrupe sus canales más visitados en pestañas, como un navegador", ru: "Группируйте часто посещаемые каналы на вкладках, например в браузере.", zh: "像浏览器一样将您经常访问的频道分组到选项卡中" },
    "Guide": { fr: "Guider", es: "Guía", ru: "Гид", zh: "指导" },
    "Guild": { fr: "Guilde", es: "gremio", ru: "Гильдия", zh: "公会" },
