    "Keybind to lock Discord (e.g. control+l)": { fr: "Combinaison de touches pour verrouiller Discord (par exemple, contrôle+l)", es: "Combinación de teclas para bloquear Discord (por ejemplo, control+l)", ru: "Привязка клавиш для блокировки Discord (например, control+l)", zh: "按键绑定以锁定 Discord（例如 control+l）" },
