    "Play soundboard sounds when you disconnect from voice.": { fr: "Jouez les sons de la table d'harmonie lorsque vous vous déconnectez de la voix.", es: "Reproduce sonidos de caja de resonancia cuando te desconectas de la voz.", ru: "Воспроизведение звуков деки при отключении от голосовой связи.", zh: "当您断开语音连接时播放音板声音。" },
    "Play the message notification sound even when its disabled": { fr: "Jouer le son de notification de message même lorsqu'il est désactivé", es: "Reproduzca el sonido de notificación del mensaje incluso cuando esté deshabilitado", ru: "Воспроизводить звук уведомления о сообщении, даже если он отключен", zh: "即使禁用时也播放消息通知声音" },
    "Play videos without carousel modal": { fr: "Lire des vidéos sans mode carrousel", es: "Reproducir vídeos sin modo carrusel", ru: "Воспроизведение видео без модального карусели", zh: "不使用轮播模式播放视频" },
