    "Quick disable. Turns off message modifying without requiring a client reload.": { fr: "Désactivation rapide. Désactive la modification des messages sans nécessiter un rechargement du client.", es: "Desactivación rápida. Desactiva la modificación de mensajes sin necesidad de recargar el cliente.", ru: "Быстрое отключение. Отключает изменение сообщения без необходимости перезагрузки клиента.", zh: "快速禁用。关闭消息修改而不需要客户端重新加载。" },
    "Quick switch": { fr: "Changement rapide", es: "Cambio rápido", ru: "Быстрый переключатель", zh: "快速开关" },
    "QuickMention": { fr: "Mention rapide", es: "Mención rápida", ru: "Быстрое упоминание", zh: "快速提及" },
    "QuickReply": { fr: "Réponse rapide", es: "Respuesta rápida", ru: "Быстрый ответ", zh: "快速回复" },
    "Quickly DM, mute, or deafen any user right from the voice-call panel.": { fr: "DM, coupez le son ou assourdissez rapidement n'importe quel utilisateur directement depuis le panneau d'appel vocal.", es: "Envía mensajes, silencia o ensordece rápidamente a cualquier usuario directamente desde el panel de llamadas de voz.", ru: "Быстро отправляйте сообщения, отключайте звук или оглушайте любого пользователя прямо с панели голосового вызова.", zh: "直接从语音通话面板快速对任何用户进行私聊、静音或聋哑。" },
    "Quickly run actions through a searchable command palette": { fr: "Exécutez rapidement des actions via une palette de commandes consultable", es: "Ejecute acciones rápidamente a través de una paleta de comandos con capacidad de búsqueda", ru: "Быстро запускайте действия с помощью палитры команд с возможностью поиска.", zh: "通过可搜索的命令面板快速运行操作" },
    "Quote Font": { fr: "Police de citation", es: "Fuente de cotización", ru: "Шрифт цитаты", zh: "报价字体" },
