    "Radius / Size of the lens": { fr: "Rayon / Taille de la lentille", es: "Radio / Tamaño de la lente", ru: "Радиус/Размер линзы", zh: "透镜半径/尺寸" },
    "RandomVoice": { fr: "Voix aléatoire", es: "voz aleatoria", ru: "Случайный голос", zh: "随机语音" },
