    "Reaction Count": { fr: "Nombre de réactions", es: "Recuento de reacciones", ru: "Количество реакций", zh: "反应计数" },
    "Reaction picker will default to Super Reactions": { fr: "Le sélecteur de réaction sera par défaut Super Réactions", es: "El selector de reacciones por defecto será Super Reacciones", ru: "В средстве выбора реакции по умолчанию будет выбран вариант «Суперреакции».", zh: "反应选择器将默认为超级反应" },
    "Reaction speed (ms) — lower = more reactive": { fr: "Vitesse de réaction (ms) — plus faible = plus réactive", es: "Velocidad de reacción (ms): menor = más reactivo", ru: "Скорость реакции (мс) — ниже = более реактивная", zh: "反应速度 (ms) — 较低 = 反应性更强" },
