    "Remove menus next to mute and deafen buttons.": { fr: "Supprimez les menus à côté des boutons de sourdine et d'assourdissement.", es: "Elimina los menús junto a los botones de silencio y sordo.", ru: "Удалите меню рядом с кнопками отключения звука и отключения звука.", zh: "删除静音和震耳欲聋按钮旁边的菜单。" },
    "Remove nameplates.": { fr: "Retirez les plaques signalétiques.", es: "Retire las placas de identificación.", ru: "Снимите таблички с именами.", zh: "取下铭牌。" },
    "Remove profile animation effects on open.": { fr: "Supprimez les effets d’animation du profil à l’ouverture.", es: "Elimina los efectos de animación del perfil al abrirlo.", ru: "Удалить эффекты анимации профиля при открытии.", zh: "删除打开时的个人资料动画效果。" },
    "Remove quests above DMs list.": { fr: "Supprimez les quêtes au-dessus de la liste des DM.", es: "Elimina las misiones que aparecen encima de la lista de mensajes directos.", ru: "Удалите квесты над списком DM.", zh: "删除 DM 列表上方的任务。" },
    "Remove requirement to hold shift for deleting a message.": { fr: "Supprimez l’obligation de maintenir Shift pour supprimer un message.", es: "Se elimina el requisito de mantener presionado el turno para eliminar un mensaje.", ru: "Удалить требование удерживать сдвиг для удаления сообщения.", zh: "删除删除消息时按住 Shift 的要求。" },
    "Remove requirement to hold shift for pinning a message.": { fr: "Supprimez l’obligation de maintenir Shift pour épingler un message.", es: "Se elimina el requisito de mantener presionada la tecla Shift para fijar un mensaje.", ru: "Удалите требование удерживать сдвиг для закрепления сообщения.", zh: "删除了按住 Shift 来固定消息的要求。" },
    "Remove server boost info above channel list.": { fr: "Supprimez les informations de boost du serveur au-dessus de la liste des chaînes.", es: "Elimine la información de mejora del servidor que aparece encima de la lista de canales.", ru: "Удалите информацию о повышении уровня сервера над списком каналов.", zh: "删除频道列表上方的服务器增强信息。" },
    "Remove shops above DMs list.": { fr: "Supprimez les boutiques au-dessus de la liste des DM.", es: "Eliminar tiendas encima de la lista de mensajes directos.", ru: "Удалить магазины из списка личных сообщений.", zh: "删除 DM 列表上方的商店。" },
    "Remove the 300ms long animation when opening or closing modals": { fr: "Supprimez l'animation de 300 ms lors de l'ouverture ou de la fermeture des modaux", es: "Eliminar la animación de 300 ms de duración al abrir o cerrar modales", ru: "Удалите анимацию длиной 300 мс при открытии или закрытии модальных окон.", zh: "删除打开或关闭模态时 300 毫秒长的动画" },
    "Remove the limit on Super Reactions playing at once": { fr: "Supprimez la limite de lecture simultanée des super réactions.", es: "Elimina el límite de reproducción de Super Reactions a la vez", ru: "Снимите ограничение на одновременное воспроизведение суперреакций.", zh: "取消超级反应同时播放的限制" },
    "Remove unavailable categories from the emoji picker.": { fr: "Supprimez les catégories indisponibles du sélecteur d'emoji.", es: "Elimina las categorías no disponibles del selector de emoji.", ru: "Удалите недоступные категории из средства выбора смайлов.", zh: "从表情符号选择器中删除不可用的类别。" },
    "Removes Discord image mosaic": { fr: "Supprime la mosaïque d’images Discord", es: "Elimina el mosaico de imágenes de Discord", ru: "Удаляет мозаику изображений Discord", zh: "删除不和谐图像马赛克" },
    "Removes the activity section above member list": { fr: "Supprime la section d'activité au-dessus de la liste des membres", es: "Elimina la sección de actividad encima de la lista de miembros.", ru: "Удаляет раздел активности над списком участников.", zh: "删除会员列表上方的活动部分" },
    "Removes the colorblind-friendly icons from statuses, just like 2015-2017 Discord": { fr: "Supprime les icônes adaptées aux daltoniens des statuts, tout comme Discord 2015-2017", es: "Elimina los íconos daltónicos de los estados, al igual que Discord 2015-2017", ru: "Удаляет из статусов значки, удобные для дальтоников, как и в Discord 2015–2017 гг.", zh: "从状态中删除色盲友好图标，就像 2015-2017 Discord 一样" },
    "Removes the gap between codeblocks and text below it": { fr: "Supprime l'espace entre les blocs de code et le texte en dessous", es: "Elimina el espacio entre los bloques de código y el texto debajo.", ru: "Устраняет разрыв между кодовыми блоками и текстом под ними.", zh: "消除代码块与其下方文本之间的间隙" },
    "Removes the loading delay when opening the menu for the first time": { fr: "Supprime le délai de chargement lors de la première ouverture du menu", es: "Elimina el retraso de carga al abrir el menú por primera vez.", ru: "Убирает задержку загрузки при первом открытии меню.", zh: "消除了第一次打开菜单时的加载延迟" },
    "Removes the ping count of incoming friend requests, message requests, and nitro offers.": { fr: "Supprime le nombre de pings des demandes d'amis entrantes, des demandes de messages et des offres nitro.", es: "Elimina el recuento de ping de las solicitudes de amistad entrantes, solicitudes de mensajes y ofertas nitro.", ru: "Удаляет счетчик пингов входящих запросов на добавление в друзья, запросов на сообщения и нитро-предложений.", zh: "删除传入好友请求、消息请求和硝基优惠的 ping 计数。" },
    "Rename": { fr: "Renommer", es: "Cambiar nombre", ru: "Переименовать", zh: "重命名" },
    "Rename Profile Configuration": { fr: "Renommer la configuration du profil", es: "Cambiar el nombre de la configuración del perfil", ru: "Переименование конфигурации профиля", zh: "重命名配置文件配置" },
    "Render GitHub-style markdown tables in Discord messages.": { fr: "Afficher les tableaux de démarques de style GitHub dans les messages Discord.", es: "Representa tablas de rebajas estilo GitHub en mensajes de Discord.", ru: "Отображение таблиц уценки в стиле GitHub в сообщениях Discord.", zh: "在 Discord 消息中渲染 GitHub 风格的 Markdown 表。" },
    "Renders magnet links like message links": { fr: "Rend les liens magnétiques comme des liens de message", es: "Representa enlaces magnéticos como enlaces de mensajes", ru: "Отображает магнитные ссылки как ссылки на сообщения.", zh: "像消息链接一样呈现磁力链接" },
    "Renders the avatars of users who reacted to a message": { fr: "Renvoie les avatars des utilisateurs qui ont réagi à un message", es: "Representa los avatares de los usuarios que reaccionaron a un mensaje.", ru: "Отображает аватары пользователей, отреагировавших на сообщение.", zh: "呈现对消息做出反应的用户的头像" },
