    "Time Period": { fr: "Période", es: "Período de tiempo", ru: "Период времени", zh: "时间段" },
    "Time in seconds notifications will be shown for.": { fr: "La durée en secondes pour laquelle les notifications seront affichées.", es: "Tiempo en segundos que se mostrarán las notificaciones.", ru: "Уведомления будут отображаться в течение времени в секундах.", zh: "将显示通知的时间（以秒为单位）。" },
    "Time to wait between each action (in seconds)": { fr: "Temps d'attente entre chaque action (en secondes)", es: "Tiempo de espera entre cada acción (en segundos)", ru: "Время ожидания между каждым действием (в секундах)", zh: "每个操作之间的等待时间（以秒为单位）" },
    "Timeout": { fr: "Délai d'attente", es: "Tiempo de espera", ru: "Тайм-аут", zh: "暂停" },
    "Timeout to allow text selection (ms)": { fr: "Délai d'expiration pour autoriser la sélection de texte (ms)", es: "Tiempo de espera para permitir la selección de texto (ms)", ru: "Тайм-аут разрешения выбора текста (мс)", zh: "允许文本选择的超时（毫秒）" },
    "Timeout to distinguish double/triple clicks (ms)": { fr: "Délai d'attente pour distinguer les doubles/triples clics (ms)", es: "Tiempo de espera para distinguir clics dobles/triples (ms)", ru: "Тайм-аут распознавания двойного/тройного щелчка (мс)", zh: "区分双击/三次点击的超时时间（毫秒）" },
    "Timers, frames, and listeners": { fr: "Minuteries, frames et auditeurs", es: "Temporizadores, fotogramas y oyentes.", ru: "Таймеры, кадры и слушатели", zh: "计时器、帧和侦听器" },
    "Timezones": { fr: "Fuseaux horaires", es: "Zonas horarias", ru: "Часовые пояса", zh: "时区" },
