    "Toast Duration Ms": { fr: "Durée du toast Mme", es: "Duración del brindis Sra.", ru: "Продолжительность тоста, мс", zh: "吐司持续时间女士" },
    "Toast hide delay (ms)": { fr: "Délai de masquage Toast (ms)", es: "Retraso de ocultación del brindis (ms)", ru: "Задержка скрытия всплывающего уведомления (мс)", zh: "Toast 隐藏延迟（毫秒）" },
    "ToastNotifications": { fr: "ToastNotifications", es: "BrindisNotificaciones", ru: "ToastNotifications", zh: "Toast通知" },
