    "Toggle Fake Deafen & Mute simultaneously": { fr: "Basculer simultanément les faux sourds et muets", es: "Alternar falso sordo y silencio simultáneamente", ru: "Переключить Fake Deafen & Mute одновременно", zh: "同时切换假聋和静音" },
    "Toggle Fake Mute": { fr: "Activer/désactiver le faux muet", es: "Alternar silencio falso", ru: "Переключить ложное отключение звука", zh: "切换假静音" },
    "Toggle clicking avatars in reactions": { fr: "Activer/désactiver les avatars en cliquant dans les réactions", es: "Alternar haciendo clic en avatares en reacciones", ru: "Переключить нажатие на аватары в реакциях", zh: "切换点击反应中的头像" },
    "Toggle functionality": { fr: "Basculer la fonctionnalité", es: "Alternar funcionalidad", ru: "Переключить функциональность", zh: "切换功能" },
    "Toggle functionality globally, for the channel, or for the guild.": { fr: "Basculez la fonctionnalité globalement, pour la chaîne ou pour la guilde.", es: "Alterna la funcionalidad globalmente, para el canal o para el gremio.", ru: "Переключение функций глобально, для канала или для гильдии.", zh: "全局切换频道或公会的功能。" },
    "Toggle functionality of your own typing indicator globally.": { fr: "Basculez la fonctionnalité de votre propre indicateur de saisie de manière globale.", es: "Cambie la funcionalidad de su propio indicador de escritura a nivel mundial.", ru: "Глобально переключите функциональность вашего собственного индикатора набора текста.", zh: "全局切换您自己的打字指示器的功能。" },
    "Toggle your signature": { fr: "Changez votre signature", es: "Alterna tu firma", ru: "Переключить свою подпись", zh: "切换您的签名" },
    "Toggle your signature (default is toggle)": { fr: "Basculez votre signature (la valeur par défaut est bascule)", es: "Alternar su firma (el valor predeterminado es alternar)", ru: "Переключить свою подпись (по умолчанию — переключить)", zh: "切换您的签名（默认为切换）" },
    "ToggleVideoBind": { fr: "ToggleVideoBind", es: "AlternarVínculo de vídeo", ru: "ToggleVideoBind", zh: "切换视频绑定" },
