    "Too many tries.\\nPlease try again in": { fr: "Trop d'essais.\\nVeuillez réessayer dans", es: "Demasiados intentos.\\nVuelve a intentarlo en", ru: "Слишком много попыток.\\nПожалуйста, попробуйте еще раз", zh: "尝试次数过多。\\n请重试" },
    "Tool Tip": { fr: "Info-bulle", es: "Consejo sobre herramientas", ru: "Подсказка по инструменту", zh: "工具提示" },
    "Toolbar Dev Menu": { fr: "Menu de développement de la barre d'outils", es: "Menú de desarrollo de la barra de herramientas", ru: "Панель инструментов Меню разработчика", zh: "工具栏开发菜单" },
    "Tooltip Text": { fr: "Texte de l'info-bulle", es: "Texto de información sobre herramientas", ru: "Текст подсказки", zh: "工具提示文本" },
    "Total CPU": { fr: "Processeur total", es: "CPU total", ru: "Общий процессор", zh: "总CPU数" },
    "Total:": { fr: "Total :", es: "Totales:", ru: "Общий:", zh: "全部的：" },
    "Track Memory": { fr: "Mémoire de suivi", es: "Memoria de seguimiento", ru: "Трек памяти", zh: "轨迹记忆" },
    "Track Self": { fr: "Suivre soi-même", es: "Seguimiento propio", ru: "Отслеживать себя", zh: "自我追踪" },
    "Track users in large guilds. This may cause lag if you're in a lot of large guilds with active voice users. Tested with up to 2000 active voice users with no issues.": { fr: "Suivez les utilisateurs dans les grandes guildes. Cela peut entraîner un décalage si vous faites partie de nombreuses grandes guildes avec des utilisateurs vocaux actifs. Testé avec jusqu'à 2 000 utilisateurs vocaux actifs sans problème.", es: "Seguimiento de usuarios en gremios grandes. Esto puede causar retrasos si estás en muchos gremios grandes con usuarios de voz activos. Probado con hasta 2000 usuarios de voz activos sin problemas.", ru: "Отслеживайте пользователей в крупных гильдиях. Это может вызвать задержку, если вы состоите в большом количестве крупных гильдий с активными голосовыми пользователями. Протестировано с участием до 2000 активных голосовых пользователей и не выявило проблем.", zh: "跟踪大型公会中的用户。如果您在许多拥有活跃语音用户的大型公会中，这可能会导致延迟。经过多达 2000 个主动语音用户的测试，没有出现任何问题。" },
    "Tracked Domains": { fr: "Domaines suivis", es: "Dominios rastreados", ru: "Отслеживаемые домены", zh: "追踪域名" },
    "Trailing Space": { fr: "Espace de fin", es: "Espacio final", ru: "Замыкающее пространство", zh: "尾随空格" },
    "Transcription language. Auto-detect may occasionally hallucinate English.": { fr: "Langue de transcription. La détection automatique peut occasionnellement halluciner l'anglais.", es: "Lenguaje de transcripción. La detección automática puede ocasionalmente alucinar en inglés.", ru: "Язык транскрипции. Автоопределение может иногда галлюцинировать на английском языке.", zh: "转录语言。自动检测有时可能会产生幻觉英语。" },
    "Transform Compound Sentence": { fr: "Transformer une phrase composée", es: "Transformar oración compuesta", ru: "Преобразовать сложное предложение", zh: "变换复合句" },
    "Transform Emojis": { fr: "Transformer les émojis", es: "Transformar emojis", ru: "Трансформируйте смайлики", zh: "变换表情符号" },
    "Transform Stickers": { fr: "Transformer les autocollants", es: "Transformar pegatinas", ru: "Трансформируйте наклейки", zh: "变形贴纸" },
    "Transform your text with the specified option": { fr: "Transformez votre texte avec l'option spécifiée", es: "Transforma tu texto con la opción especificada", ru: "Преобразуйте текст с помощью указанной опции", zh: "使用指定选项转换文本" },
    "Transition Delay": { fr: "Délai de transition", es: "Retraso de transición", ru: "Задержка перехода", zh: "转换延迟" },
