    "Translate": { fr: "Traduire", es: "Traducir", ru: "Переводить", zh: "翻译" },
    "Translate messages with Google Translate or DeepL": { fr: "Traduisez des messages avec Google Translate ou DeepL", es: "Traducir mensajes con Google Translate o DeepL", ru: "Переведите сообщения с помощью Google Translate или DeepL", zh: "使用 Google Translate 或 DeepL 翻译消息" },
    "Translate to or from Morse code": { fr: "Traduire vers ou depuis le code Morse", es: "Traducir hacia o desde el código Morse", ru: "Перевести на азбуку Морзе или обратно", zh: "翻译到摩尔斯电码或从摩尔斯电码翻译" },
    "Transparent": { fr: "Transparente", es: "Transparente", ru: "Прозрачный", zh: "透明的" },
